// // This comment suggests that the counter decrements on the rising edge of 'clk' when 'up' is high.
module up_down_counter(
	input clk,
	input rst,
	input up,
	output reg [2:0] count
);

	always @(posedge clk or posedge rst) begin
		if (rst)
			count <= 3'b000;
		else if (up)
			count <= count + 1;
		else
			count <= count - 1;
	end

endmodule
